// ── Validate & Sanitize User Input ──
const input = $input.first().json;
let body = input.body || input;
// Handle text/plain body (CORS fix - body may arrive as raw JSON string)
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
const rawMessage = body.message;
const sessionId = (body.session_id || 'anonymous').toString().trim();
const language = (body.language || '').toString().trim();

if (!rawMessage || typeof rawMessage !== 'string') {
  return [{
    json: {
      valid: false,
      error: 'Please enter a message to get started.',
      message: '',
      sessionId
    }
  }];
}

const message = rawMessage.trim();

if (message.length < 2) {
  return [{
    json: {
      valid: false,
      error: 'Please provide a bit more detail so I can help you.',
      message: '',
      sessionId
    }
  }];
}

if (message.length > 2000) {
  return [{
    json: {
      valid: false,
      error: 'Your message is too long. Please keep it under 2000 characters.',
      message: '',
      sessionId
    }
  }];
}

return [{
  json: {
    valid: true,
    error: null,
    message,
    sessionId,
    language
  }
}];

// ── Build System Prompt + API Request Body ──
const _in = $input.first().json;
const userMessage = _in.message;
// Reply language: honour the forwarded hint, else auto-detect from the script.
let _lang = _in.language;
if (!_lang) {
  if (/[஀-௿]/.test(userMessage)) _lang = 'ta';
  else if (/[ऀ-ॿ]/.test(userMessage)) _lang = 'hi';
  else if (/[ఀ-౿]/.test(userMessage)) _lang = 'te';
  else _lang = 'en';
}
const _LANG_NAMES = { en: 'English', ta: 'Tamil', hi: 'Hindi', te: 'Telugu' };
const languageName = _LANG_NAMES[_lang] || 'English';
const languageInstruction = '\n\nLANGUAGE (CRITICAL): Reply ONLY in ' + languageName + '. Always answer in the SAME language the user wrote in (English or Tamil). If the user writes in English, reply in English; if the user writes in Tamil, reply in Tamil. Never reply in Tamil to an English message, and never reply in English to a Tamil message. Keep official acronyms and emergency numbers (PWD, NHAI, 112, 108) unchanged.';

const systemPrompt = `You are Saalai Kural Assistant -- a calm, clear, and helpful citizen guide for road safety and civic road awareness in India.

ROLE AND IDENTITY
- You help civilians understand road safety, describe road issues, and navigate common civic road questions.
- You provide practical, actionable guidance in simple language.
- You are NOT a police officer, lawyer, doctor, ambulance dispatcher, or government official.
- You do not have enforcement authority or access to official databases.

WHAT YOU DO
- Answer road safety questions with practical tips.
- Help users describe road problems clearly (potholes, broken signals, dangerous stretches, waterlogging, missing signage).
- Explain what information to collect before filing a road-issue complaint.
- Share common traffic rules and road etiquette in India using simple language.
- Suggest the right authority to contact (municipal corporation, traffic police, NHAI, PWD) when relevant.
- Give step-by-step guidance when useful.
- Ask clarifying questions when the user's situation is unclear.

WHAT YOU NEVER DO
- Never invent specific fine amounts, penalty numbers, or legal section numbers unless you are 100% certain they are correct.
- Never give medical advice or attempt emergency dispatch.
- Never instruct users to take physically unsafe actions.
- Never pretend to file complaints, access databases, or contact authorities on behalf of the user.
- Never present uncertain information as certain fact.
- Never respond to topics completely unrelated to road safety, road issues, traffic rules, or civic road matters.

SAFETY AND ACCURACY RULES
- If someone describes an active emergency (accident with injuries, fire, vehicle trapping someone), immediately advise calling 112 (India unified emergency number) FIRST, then provide calm further guidance.
- Always distinguish clearly between general guidance and information that should be verified with official sources.
- When you are unsure about something, say so honestly and recommend the user verify with the relevant authority.
- If a question is outside your scope, politely explain your boundaries and redirect.

RESPONSE STYLE
- Be concise: 2-5 sentences for simple questions, numbered bullet points for multi-step guidance.
- Use simple, jargon-free language that anyone can understand.
- Be calm and reassuring, especially for stressful situations like accidents.
- End with one helpful follow-up suggestion or next step.
- Do not use markdown headers or heavy formatting -- keep responses natural and conversational.

INDIA CONTEXT
- Common helplines: 112 (unified emergency), 100 (police), 108 (ambulance in many states), 1073 (road accident helpline in some states).
- When suggesting authorities: Municipal Corporation / Nagar Palika (city roads), PWD (state highways), NHAI (national highways), Traffic Police (violations/signals).
- Common road challenges: potholes, waterlogging, encroachment, poor lighting, stray animals, construction hazards, missing lane markings, broken traffic signals.`;

const requestBody = {
  model: 'openai/gpt-oss-20b',
  messages: [
    { role: 'system', content: systemPrompt + languageInstruction },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.7,
  max_tokens: 1024,
  top_p: 0.9
};

return [{ json: { requestBody, userMessage } }];

// ── Parse API Response & Build Structured Output ──
try {
  const data = $input.first().json;

  // Retrieve original user message from Build Prompt node
  let userMessage = '';
  try {
    userMessage = $('Build Prompt').first().json.userMessage || '';
  } catch (e) {
    userMessage = '';
  }

  // Check for API-level errors
  if (data.error) {
    const errMsg = typeof data.error === 'string' ? data.error : (data.error.message || 'API error');
    throw new Error(errMsg);
  }

  // Check for valid response structure
  if (!data.choices || !Array.isArray(data.choices) || data.choices.length === 0) {
    throw new Error('No response generated by the model');
  }

  const reply = (data.choices[0].message && data.choices[0].message.content)
    ? data.choices[0].message.content.trim()
    : '';

  if (!reply) {
    throw new Error('Empty response from AI');
  }

  // ── Categorize based on user message ──
  const lower = userMessage.toLowerCase();
  let category = 'general';
  let guidanceType = 'general_guidance';

  if (/accident|emergency|injured|fire|trapped|bleeding|crash|collisi/.test(lower)) {
    category = 'emergency';
    guidanceType = 'emergency_action';
  } else if (/pothole|damage|broken|crack|waterlog|obstruct|block|construction|report|complaint|grievance|flooded/.test(lower)) {
    category = 'road_issue';
  } else if (/rule|signal|speed|license|fine|challan|penalty|violation|overtake|lane|parking|drunk|red.light|zebra/.test(lower)) {
    category = 'traffic_rules';
    guidanceType = 'verify_with_authorities';
  } else if (/safe|helmet|seatbelt|seat.belt|pedestrian|crossing|school.zone|night.driv|fog|rain|visibility/.test(lower)) {
    category = 'road_safety';
  }

  // Check if reply mentions verification needs
  const replyLower = reply.toLowerCase();
  if (replyLower.includes('verify') || replyLower.includes('check with') || replyLower.includes('confirm with') || replyLower.includes('official source')) {
    guidanceType = 'verify_with_authorities';
  }

  // ── Follow-up suggestions by category ──
  const followUps = {
    emergency: ['What should I do at an accident scene?', 'How do I help an injured person safely?'],
    road_issue: ['How do I file a formal complaint?', 'What details should I collect?', 'Which authority handles this?'],
    traffic_rules: ['Where can I verify this officially?', 'What documents should I always carry?'],
    road_safety: ['Tips for two-wheeler safety?', 'How to stay safe as a pedestrian?'],
    general: ['Road safety tips', 'How to report a road issue', 'Common traffic rules in India']
  };

  return [{
    json: {
      success: true,
      reply,
      category,
      guidance_type: guidanceType,
      follow_up_options: followUps[category] || followUps.general
    }
  }];

} catch (err) {
  return [{
    json: {
      success: false,
      reply: 'I am experiencing a temporary issue. Please try again in a moment. If this persists, you can contact your local municipal helpline directly.',
      category: 'error',
      guidance_type: 'general_guidance',
      follow_up_options: ['Try asking again', 'What can you help me with?']
    }
  }];
}

// ── Prepare Error Response for Invalid Input ──
const errorMsg = $input.first().json.error || 'Something went wrong. Please try again.';

return [{
  json: {
    success: false,
    reply: errorMsg,
    category: 'error',
    guidance_type: 'general_guidance',
    follow_up_options: [
      'What can you help me with?',
      'Road safety tips',
      'How to report a road issue'
    ]
  }
}];
